     1→import { useInfiniteQuery } from '@tanstack/react-query';
     2→import './sidebarOpinions.css'
     3→import { getOpinions } from '../../../API/Api';
     4→import { useNavigate } from 'react-router-dom';
     5→import { handleClickProfile } from '../../../helpers/handleClicks';
     6→import { useAuth } from '../../Context/useAuth';
     7→import { BarLoader, MoonLoader } from 'react-spinners';
     8→
     9→const SidebarOpinions = ({openEditor}) =>{
    10→    const {user, session, openAuthModal} = useAuth();
    11→
    12→    const handleOpenEditor = () =>{
    13→        if(!session) return openAuthModal();
    14→        openEditor();
    15→    }
    16→    const navigate = useNavigate();
    17→
    18→    const handleClickOpionionsProfileOriginal = handleClickProfile(navigate);
    19→    const handleClickOpionionsProfile = (e, loggedInUserId, clickedUserId) => {
    20→        if(!session){
    21→            e.stopPropagation();
    22→            return openAuthModal();
    23→        }
    24→        handleClickOpionionsProfileOriginal(e, loggedInUserId, clickedUserId);
    25→    };
    26→
    27→    const {data, isLoading, fetchNextPage, isFetchingNextPage, hasNextPage} = useInfiniteQuery({
    28→        queryKey: ['getOpinions'],
    29→        queryFn: ({pageParam = null}) => getOpinions(pageParam, 5),
    30→        getNextPageParam: (lastPage) =>{
    31→            if(lastPage?.hasMore){
    32→                const lastOpinion = lastPage?.data[lastPage?.data?.length - 1];
    33→                return lastOpinion.id;
    34→            } else {
    35→                return undefined
    36→            }
    37→        },
    38→        refetchOnWindowFocus: false,
    39→    });
    40→
    41→    const handleClickSeeMore = () =>{
    42→        if(!isLoading && !isFetchingNextPage){
    43→            fetchNextPage();;
    44→        }
    45→        
    46→    }
    47→
    48→    const handleClickContent = (e, opinionId, userId) =>{
    49→        e.stopPropagation();
    50→        if(!session) return openAuthModal();
    51→        navigate('/home/opinionsViewer', {
    52→            state: {
    53→                opinionId: opinionId,
    54→                userId: userId
    55→            }
    56→        })
    57→    }
    58→
    59→    // useEffect(() => {
    60→    //     console.log(data)
    61→    // }, [data])
    62→
    63→    const opinions = data?.pages.flatMap((page) => page.data) || [];
    64→    
    65→    if(opinions.length === 0){
    66→        return(
    67→            <div className='side-bar-opinions-parent-container'>
    68→                <div className='signal-container'>
    69→                    <p className='signal-header'>“Share what you believe. This is a free-speech space.”</p>
    70→                    <button onClick={() => handleOpenEditor()} className='write-opinions-bttn'>
    71→                        Write opinions
    72→                    </button>
    73→                </div>
    74→                <div className='latest-opinions-container'>
    75→                    <div className='latest-opinions-header'>
    76→                        Latest opinions
    77→                    </div>
    78→                    <div className='sidebar-opinions-cards-container'>
    79→                        No opinions availabe
    80→                    </div>
    81→                </div>
    82→            </div>
    83→        )
    84→    }
    85→    if(isLoading){
    86→        return(
    87→            <div className='side-bar-opinions-parent-container'>
    88→                <div className='opinions-loading-container'>
    89→                    <MoonLoader size={25} speedMultiplier={1} loading={isLoading}/>
    90→                </div>
    91→            </div>
    92→        )
    93→    }
    94→    return(
    95→        <>
    96→        <div className="side-bar-opinions-parent-container">
    97→            <div className='signal-container'>
    98→                <p className='signal-header'>“Share what you believe. This is a free-speech space.”</p>
    99→                <button onClick={() => handleOpenEditor()} className='write-opinions-bttn'>
   100→                    Write opinions
   101→                </button>
   102→            </div>
   103→
   104→            <div className='latest-opinions-container'>
   105→                <div className='latest-opinions-header'>
   106→                    Latest opinions
   107→                </div>
   108→                <div className='sidebar-opinions-cards-container'>
   109→                    {opinions.map((opinionsData) => (
   110→                        <div key={opinionsData.id} className="so-card">
   111→                            <div className="so-user-row">
   112→                                <img onClick={(e) => handleClickOpionionsProfile(e, user?.userData[0].id, opinionsData.user_id)} className="so-avatar" src={opinionsData.users.image_url || "../../assets/profile.jpg"} alt="" />
   113→                                <span onClick={(e) => handleClickOpionionsProfile(e, user?.userData[0].id, opinionsData.user_id)} className="so-username">{opinionsData.users.name}</span>
   114→                            </div>
   115→                            <div className="so-body" onClick={(e) => handleClickContent(e, opinionsData.id, opinionsData.user_id)}>
   116→                                {opinionsData.opinion}
   117→                            </div>
   118→                            <div className="so-meta-bar">
   119→                                <span className="so-reply-pill" onClick={(e) => { e.stopPropagation(); if(!session) return openAuthModal(); navigate('/home/opinionsViewer', { state: { opinionId: opinionsData.id, userId: opinionsData.user_id } }); }}>
   120→                                    <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
   121→                                        <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
   122→                                    </svg>
   123→                                    Reply
   124→                                </span>
   125→                            </div>
   126→                        </div>
   127→                    ))}
   128→                    {hasNextPage && (
   129→                        <div onClick={() => handleClickSeeMore()} className='see-fullpage-bttn'>
   130→                            See more
   131→                        </div>
   132→                    )}
   133→                    
   134→                </div>
   135→            </div>
   136→        </div>
   137→        </>
   138→    )
   139→}
   140→export default SidebarOpinions;

