     1→import { useInfiniteQuery, useQueryClient } from "@tanstack/react-query";
     2→import { addReplyOpinion, getOpinionReply } from "../../../API/Api";
     3→import { useState, useRef } from "react";
     4→import { useAuth } from "../../Context/useAuth";
     5→import { motion, AnimatePresence } from "framer-motion";
     6→import formatPostDate from "../../../helpers/formatDateString";
     7→
     8→const MAX_VISUAL_DEPTH = 4;
     9→
    10→const OpinionsReplyCard = ({ opinionId, depth = 0 }) => {
    11→    const queryClient = useQueryClient();
    12→    const { user } = useAuth();
    13→
    14→    const [showReply, setShowReply] = useState(false);
    15→    const [replyOpinion, setReplyOpinion] = useState('');
    16→    const [isTypingId, setIsTypingId] = useState('');
    17→    const [showReplyButtonId, setShowReplyButtonId] = useState('');
    18→
    19→    const textAreaRef = useRef(null);
    20→
    21→    const { data, isLoading, hasNextPage, isFetchingNextPage, fetchNextPage } = useInfiniteQuery({
    22→        queryKey: ['getReplyOpinion', opinionId],
    23→        queryFn: ({ queryKey, pageParam = null }) => getOpinionReply(queryKey[1], 10, pageParam),
    24→        getNextPageParam: (lastPage) => {
    25→            if (lastPage?.hasMore) {
    26→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
    27→                return lastReply.id;
    28→            }
    29→            return undefined;
    30→        },
    31→        enabled: !!opinionId,
    32→        refetchOnWindowFocus: false
    33→    });
    34→
    35→    const handleSubmitReplyOpinion = async (reply, receiver_id, sender_id, parent_id) => {
    36→        try {
    37→            const formadata = new FormData();
    38→            formadata.append('opinion', reply);
    39→            await addReplyOpinion(formadata, receiver_id, sender_id, parent_id);
    40→            queryClient.invalidateQueries(['getReplyOpinion', opinionId]);
    41→            setReplyOpinion('');
    42→            if (textAreaRef.current) {
    43→                textAreaRef.current.innerText = '';
    44→            }
    45→        } catch (error) {
    46→            console.error(error);
    47→            setReplyOpinion('');
    48→            if (textAreaRef.current) {
    49→                textAreaRef.current.innerText = '';
    50→            }
    51→            queryClient.invalidateQueries(['getReplyOpinion', opinionId]);
    52→        }
    53→    };
    54→
    55→    const cancelTyping = () => {
    56→        setIsTypingId('');
    57→        setReplyOpinion('');
    58→        if (textAreaRef.current) {
    59→            textAreaRef.current.innerText = '';
    60→            textAreaRef.current.blur();
    61→        }
    62→        setShowReplyButtonId('');
    63→    };
    64→
    65→    const visualDepth = Math.min(depth, MAX_VISUAL_DEPTH);
    66→    const opinioData = data?.pages.flatMap((page) => page.data) || [];
    67→
    68→    return (
    69→        <div
    70→            className="rc-thread"
    71→            style={{ '--depth': visualDepth }}
    72→        >
    73→            {opinioData?.map((opinion, index) => (
    74→                <motion.div
    75→                    className="rc-card"
    76→                    key={opinion.id}
    77→                    initial={{ opacity: 0, y: 6 }}
    78→                    animate={{ opacity: 1, y: 0 }}
    79→                    transition={{ duration: 0.25, delay: index * 0.03, ease: "easeOut" }}
    80→                >
    81→                    {depth > 0 && <div className="rc-thread-line" />}
    82→
    83→                    <div className="rc-content">
    84→                        <div className="rc-user-row">
    85→                            <img
    86→                                className="rc-avatar"
    87→                                src={opinion.users?.image_url || '../assets/profile.jpg'}
    88→                                alt=""
    89→                            />
    90→                            <span className="rc-username">{opinion.users?.name}</span>
    91→                            <span className="rc-dot">·</span>
    92→                            <span className="rc-date">{formatPostDate(opinion.created_at)}</span>
    93→                        </div>
    94→
    95→                        <div className="rc-body">
    96→                            {opinion.opinion}
    97→                        </div>
    98→
    99→                        <div className="rc-action-row">
   100→                            {opinion.reply_count > 0 && (
   101→                                <button
   102→                                    className="rc-toggle-btn"
   103→                                    onClick={() => setShowReply(prev => !prev)}
   104→                                >
   105→                                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
   106→                                        <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
   107→                                    </svg>
   108→                                    {showReply ? 'Hide' : 'Show'} {opinion.reply_count} {opinion.reply_count === 1 ? 'reply' : 'replies'}
   109→                                </button>
   110→                            )}
   111→                            <button
   112→                                className="rc-toggle-btn"
   113→                                onClick={() => setShowReplyButtonId(
   114→                                    showReplyButtonId === opinion.id ? '' : opinion.id
   115→                                )}
   116→                            >
   117→                                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
   118→                                    <polyline points="9 17 4 12 9 7" />
   119→                                    <path d="M20 18v-2a4 4 0 0 0-4-4H4" />
   120→                                </svg>
   121→                                Reply
   122→                            </button>
   123→                        </div>
   124→
   125→                        <AnimatePresence>
   126→                            {showReplyButtonId === opinion.id && (
   127→                                <motion.div
   128→                                    initial={{ height: 0, opacity: 0 }}
   129→                                    animate={{ height: "auto", opacity: 1 }}
   130→                                    exit={{ height: 0, opacity: 0 }}
   131→                                    transition={{ duration: 0.2 }}
   132→                                    className="rc-reply-input-wrapper"
   133→                                >
   134→                                    <div
   135→                                        className="ov-reply-input"
   136→                                        onFocus={() => setIsTypingId(opinion.id)}
   137→                                        ref={textAreaRef}
   138→                                        onInput={(e) => setReplyOpinion(e.currentTarget.innerText.trim())}
   139→                                        data-placeholder={`Add a reply to '${opinion.users?.name}'`}
   140→                                        contentEditable="true"
   141→                                        role="textbox"
   142→                                    />
   143→
   144→                                    {isTypingId === opinion.id && (
   145→                                        <div className="ov-btn-row">
   146→                                            <button onClick={cancelTyping} className="ov-btn-cancel">Cancel</button>
   147→                                            <button
   148→                                                disabled={replyOpinion.trim().length === 0}
   149→                                                onClick={() => handleSubmitReplyOpinion(replyOpinion, opinion.users.id, user?.userData[0].id, opinion.id)}
   150→                                                className={`ov-btn-submit ${replyOpinion.trim().length === 0 ? 'ov-btn-disabled' : ''}`}
   151→                                            >
   152→                                                Submit
   153→                                            </button>
   154→                                        </div>
   155→                                    )}
   156→                                </motion.div>
   157→                            )}
   158→                        </AnimatePresence>
   159→
   160→                        <AnimatePresence>
   161→                            {showReply && (
   162→                                <motion.div
   163→                                    initial={{ opacity: 0 }}
   164→                                    animate={{ opacity: 1 }}
   165→                                    exit={{ opacity: 0 }}
   166→                                    transition={{ duration: 0.2 }}
   167→                                >
   168→                                    <OpinionsReplyCard opinionId={opinion.id} depth={depth + 1} />
   169→                                </motion.div>
   170→                            )}
   171→                        </AnimatePresence>
   172→                    </div>
   173→                </motion.div>
   174→            ))}
   175→
   176→            {hasNextPage && (
   177→                <button className="rc-load-more" onClick={() => fetchNextPage()}>
   178→                    {isFetchingNextPage ? 'Loading...' : 'Show more replies'}
   179→                </button>
   180→            )}
   181→        </div>
   182→    );
   183→};
   184→
   185→export default OpinionsReplyCard;
   186→

